import React, { useState, useMemo } from 'react';

const T = {
  bg: '#0a0a0a', surface: '#111111', surfaceAlt: '#1a1a1a',
  border: '#2a2a2a', text: '#fafafa', textSec: '#a1a1aa',
  muted: '#52525b', blue: '#38bdf8', yellow: '#fbbf24',
  green: '#10b981', red: '#f43f5e', purple: '#8b5cf6',
  orange: '#fb923c', font: "'JetBrains Mono', monospace",
};

function softmax(x) {
  const m = Math.max(...x);
  const e = x.map(v => Math.exp(v - m));
  const s = e.reduce((a, b) => a + b, 0);
  return e.map(v => v / s);
}

function cumReturns(rewards) {
  const r = [...rewards];
  for (let i = r.length - 2; i >= 0; i--) r[i] += r[i + 1];
  return r;
}

function computeGrad(theta, episodes) {
  const g = [[0, 0], [0, 0]];
  for (const ep of episodes) {
    const rets = cumReturns(ep.map(s => s[2]));
    for (let t = 0; t < ep.length; t++) {
      const [s, a] = ep[t];
      const G = rets[t];
      const p = softmax(theta[s]);
      for (let j = 0; j < 2; j++) {
        g[s][j] += ((j === a ? 1 : 0) - p[j]) * G;
      }
    }
  }
  const N = episodes.length;
  return g.map(r => r.map(v => v / N));
}

const SmallBtn = ({ onClick, children, color }) => (
  <button onClick={onClick} style={{
    background: 'none', border: '1px solid ' + T.border, borderRadius: 3,
    width: 18, height: 18, cursor: 'pointer', display: 'flex',
    alignItems: 'center', justifyContent: 'center', fontSize: 12,
    fontWeight: 700, fontFamily: T.font, color: color || T.textSec, padding: 0,
  }}>{children}</button>
);

export default function App() {
  const [theta, setTheta] = useState([[0, 0], [0, 0]]);
  const [ep1R, setEp1R] = useState([0, 1]);
  const [ep2R, setEp2R] = useState([0]);

  const ep1Struct = [[0, 1], [1, 0]];
  const ep2Struct = [[0, 0]];

  const episodes = useMemo(() => [
    ep1Struct.map((sa, i) => [sa[0], sa[1], ep1R[i]]),
    ep2Struct.map((sa, i) => [sa[0], sa[1], ep2R[i]]),
  ], [ep1R, ep2R]);

  const { probs, grad, ret1, ret2 } = useMemo(() => ({
    probs: [softmax(theta[0]), softmax(theta[1])],
    grad: computeGrad(theta, episodes),
    ret1: cumReturns(ep1R),
    ret2: cumReturns(ep2R),
  }), [theta, episodes, ep1R, ep2R]);

  const adjTheta = (s, a, d) => setTheta(p => {
    const n = p.map(r => [...r]);
    n[s][a] = Math.round(Math.max(-3, Math.min(3, n[s][a] + d)) * 10) / 10;
    return n;
  });

  const setR = (ep, i, v) => {
    v = Math.round(Math.max(-3, Math.min(3, v)) * 10) / 10;
    if (ep === 0) setEp1R(p => { const n = [...p]; n[i] = v; return n; });
    else setEp2R(p => { const n = [...p]; n[i] = v; return n; });
  };

  const gMax = Math.max(...grad.flat().map(Math.abs), 0.01);

  const gBg = v => {
    const t = Math.min(Math.abs(v) / gMax, 1);
    if (v > 0.001) return `rgba(16,185,129,${(0.1 + t * 0.35).toFixed(2)})`;
    if (v < -0.001) return `rgba(244,63,94,${(0.1 + t * 0.35).toFixed(2)})`;
    return 'rgba(255,255,255,0.03)';
  };

  const gCol = v => v > 0.001 ? T.green : v < -0.001 ? T.red : T.muted;

  const insight = useMemo(() => {
    const allZ = grad.flat().every(v => Math.abs(v) < 0.001);
    if (allZ) return { text: 'All returns are zero. No gradient signal - nothing to reinforce!', icon: 'O' };
    let mV = 0, mS = 0, mA = 0;
    grad.forEach((r, s) => r.forEach((v, a) => { if (Math.abs(v) > Math.abs(mV)) { mV = v; mS = s; mA = a; } }));
    const d = mV > 0 ? 'increase' : 'decrease';
    return {
      text: `Strongest push: ${d} A${mA} in S${mS} (${mV > 0 ? '+' : ''}${mV.toFixed(3)}). ${mV > 0 ? 'Good returns reinforce this choice.' : 'Returns discourage this choice.'}`,
      icon: mV > 0 ? '+' : '-',
    };
  }, [grad]);

  const presets = [
    { l: 'Default', e1: [0, 1], e2: [0], th: [[0, 0], [0, 0]] },
    { l: 'Negative', e1: [0, -2], e2: [0], th: [[0, 0], [0, 0]] },
    { l: 'Conflict', e1: [0, 2], e2: [2], th: [[0, 0], [0, 0]] },
    { l: 'Biased', e1: [0, 1], e2: [0], th: [[1, -1], [-1, 1]] },
  ];

  const applyPreset = p => { setEp1R(p.e1); setEp2R(p.e2); setTheta(p.th.map(r => [...r])); };

  const Arrow = ({ val, size }) => {
    if (Math.abs(val) < 0.001) return null;
    const h = Math.max(6, Math.min(18, (Math.abs(val) / gMax) * 18));
    const up = val > 0;
    const col = up ? T.green : T.red;
    return (
      <svg width={12} height={22} style={{ display: 'block', margin: '0 auto' }}>
        <line x1={6} y1={up ? 20 : 2} x2={6} y2={up ? 20 - h : 2 + h} stroke={col} strokeWidth={2} />
        <polygon points={up ? '2,' + (22 - h) + ' 10,' + (22 - h) + ' 6,' + (20 - h - 4) : '2,' + (2 + h) + ' 10,' + (2 + h) + ' 6,' + (6 + h)} fill={col} />
      </svg>
    );
  };

  const RewardSlider = ({ value, onChange, label }) => (
    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 3 }}>
      <div style={{ fontSize: 9, color: T.muted, letterSpacing: 1 }}>{label}</div>
      <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
        <SmallBtn onClick={() => onChange(value - 0.5)}>-</SmallBtn>
        <div style={{
          fontFamily: T.font, fontSize: 16, fontWeight: 700, width: 36,
          textAlign: 'center', color: value > 0 ? T.green : value < 0 ? T.red : T.textSec,
          transition: 'color 0.2s',
        }}>{value.toFixed(1)}</div>
        <SmallBtn onClick={() => onChange(value + 0.5)}>+</SmallBtn>
      </div>
      <input type="range" min={-3} max={3} step={0.5} value={value}
        onChange={e => onChange(parseFloat(e.target.value))}
        style={{ width: 72, accentColor: T.purple, cursor: 'pointer' }} />
    </div>
  );

  const stateLabels = ['S0', 'S1'];
  const actionLabels = ['A0', 'A1'];

  return (
    <div style={{ background: T.bg, minHeight: '100vh', fontFamily: T.font, color: T.text, display: 'flex', justifyContent: 'center', padding: '12px 8px' }}>
      <div style={{ maxWidth: 580, width: '100%' }}>
        {/* Title */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 10 }}>
          <div>
            <div style={{ fontSize: 17, fontWeight: 700, letterSpacing: -0.5 }}>REINFORCE Policy Gradient</div>
            <div style={{ fontSize: 10, color: T.muted, marginTop: 2 }}>Adjust rewards to see how gradients reinforce actions</div>
          </div>
          <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap', justifyContent: 'flex-end' }}>
            {presets.map((p, i) => (
              <button key={i} onClick={() => applyPreset(p)} style={{
                background: T.surfaceAlt, border: '1px solid ' + T.border, borderRadius: 4,
                padding: '3px 7px', fontSize: 9, color: T.textSec, cursor: 'pointer', fontFamily: T.font,
              }}>{p.l}</button>
            ))}
          </div>
        </div>

        {/* Episodes - THE MAIN INTERACTION */}
        <div style={{ background: T.surface, borderRadius: 10, padding: 14, marginBottom: 10 }}>
          <div style={{ fontSize: 11, color: T.purple, fontWeight: 600, marginBottom: 10, letterSpacing: 0.5 }}>EPISODES (adjust rewards)</div>

          {/* Episode 1 */}
          <div style={{ marginBottom: 12 }}>
            <div style={{ fontSize: 10, color: T.muted, marginBottom: 6 }}>Episode 1</div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 6, flexWrap: 'wrap' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                <div style={{ background: T.surfaceAlt, borderRadius: 6, padding: '6px 8px', border: '1px solid ' + T.border, textAlign: 'center', minWidth: 110 }}>
                  <div style={{ fontSize: 9, color: T.muted, marginBottom: 3 }}>t=0: S0, takes A1</div>
                  <RewardSlider value={ep1R[0]} onChange={v => setR(0, 0, v)} label="REWARD" />
                  <div style={{ fontSize: 9, color: T.yellow, marginTop: 3 }}>G = {ret1[0].toFixed(1)}</div>
                </div>
                <svg width={20} height={20}><line x1={0} y1={10} x2={14} y2={10} stroke={T.muted} strokeWidth={1.5}/><polygon points="14,6 20,10 14,14" fill={T.muted}/></svg>
                <div style={{ background: T.surfaceAlt, borderRadius: 6, padding: '6px 8px', border: '1px solid ' + T.border, textAlign: 'center', minWidth: 110 }}>
                  <div style={{ fontSize: 9, color: T.muted, marginBottom: 3 }}>t=1: S1, takes A0</div>
                  <RewardSlider value={ep1R[1]} onChange={v => setR(0, 1, v)} label="REWARD" />
                  <div style={{ fontSize: 9, color: T.yellow, marginTop: 3 }}>G = {ret1[1].toFixed(1)}</div>
                </div>
              </div>
            </div>
          </div>

          {/* Episode 2 */}
          <div>
            <div style={{ fontSize: 10, color: T.muted, marginBottom: 6 }}>Episode 2</div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
              <div style={{ background: T.surfaceAlt, borderRadius: 6, padding: '6px 8px', border: '1px solid ' + T.border, textAlign: 'center', minWidth: 110 }}>
                <div style={{ fontSize: 9, color: T.muted, marginBottom: 3 }}>t=0: S0, takes A0</div>
                <RewardSlider value={ep2R[0]} onChange={v => setR(1, 0, v)} label="REWARD" />
                <div style={{ fontSize: 9, color: T.yellow, marginTop: 3 }}>G = {ret2[0].toFixed(1)}</div>
              </div>
            </div>
          </div>
        </div>

        {/* Policy + Gradient side by side */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: 10 }}>
          {/* Policy theta */}
          <div style={{ background: T.surface, borderRadius: 10, padding: 12 }}>
            <div style={{ fontSize: 11, color: T.blue, fontWeight: 600, marginBottom: 8, letterSpacing: 0.5 }}>POLICY theta</div>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr>
                  <td style={{ fontSize: 9, color: T.muted, padding: 3 }}></td>
                  {actionLabels.map((a, i) => <td key={i} style={{ fontSize: 10, color: T.blue, textAlign: 'center', padding: 3, fontWeight: 600 }}>{a}</td>)}
                </tr>
              </thead>
              <tbody>
                {stateLabels.map((s, si) => (
                  <tr key={si}>
                    <td style={{ fontSize: 10, color: T.blue, fontWeight: 600, padding: 3 }}>{s}</td>
                    {[0, 1].map(ai => (
                      <td key={ai} style={{ textAlign: 'center', padding: 3 }}>
                        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 2 }}>
                          <SmallBtn onClick={() => adjTheta(si, ai, -0.5)} color={T.muted}>-</SmallBtn>
                          <span style={{ fontSize: 13, fontWeight: 600, width: 32, textAlign: 'center', color: T.text }}>{theta[si][ai].toFixed(1)}</span>
                          <SmallBtn onClick={() => adjTheta(si, ai, 0.5)} color={T.muted}>+</SmallBtn>
                        </div>
                        <div style={{ fontSize: 9, color: T.textSec, marginTop: 2 }}>pi={probs[si][ai].toFixed(2)}</div>
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Gradient Result */}
          <div style={{ background: T.surface, borderRadius: 10, padding: 12 }}>
            <div style={{ fontSize: 11, color: T.green, fontWeight: 600, marginBottom: 8, letterSpacing: 0.5 }}>GRADIENT</div>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr>
                  <td style={{ fontSize: 9, color: T.muted, padding: 3 }}></td>
                  {actionLabels.map((a, i) => <td key={i} style={{ fontSize: 10, color: T.textSec, textAlign: 'center', padding: 3, fontWeight: 600 }}>{a}</td>)}
                </tr>
              </thead>
              <tbody>
                {stateLabels.map((s, si) => (
                  <tr key={si}>
                    <td style={{ fontSize: 10, color: T.textSec, fontWeight: 600, padding: 3 }}>{s}</td>
                    {[0, 1].map(ai => (
                      <td key={ai} style={{ textAlign: 'center', padding: 3 }}>
                        <div style={{
                          background: gBg(grad[si][ai]), borderRadius: 6, padding: '4px 2px',
                          transition: 'all 0.3s', border: '1px solid ' + (Math.abs(grad[si][ai]) > 0.001 ? gCol(grad[si][ai]) + '33' : T.border),
                        }}>
                          <Arrow val={grad[si][ai]} />
                          <div style={{
                            fontSize: 14, fontWeight: 700, color: gCol(grad[si][ai]),
                            transition: 'color 0.3s',
                          }}>{grad[si][ai] >= 0 ? '+' : ''}{grad[si][ai].toFixed(3)}</div>
                        </div>
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Gradient Visualization Bar */}
        <div style={{ background: T.surface, borderRadius: 10, padding: 14, marginBottom: 10 }}>
          <div style={{ fontSize: 10, color: T.muted, marginBottom: 8 }}>Gradient direction per state-action pair</div>
          {stateLabels.map((s, si) => (
            <div key={si} style={{ marginBottom: si === 0 ? 8 : 0 }}>
              <div style={{ fontSize: 9, color: T.muted, marginBottom: 3 }}>{s}</div>
              <div style={{ display: 'flex', gap: 6 }}>
                {actionLabels.map((a, ai) => {
                  const v = grad[si][ai];
                  const pct = Math.abs(v) / gMax;
                  const isPos = v > 0.001;
                  const isNeg = v < -0.001;
                  return (
                    <div key={ai} style={{ flex: 1 }}>
                      <div style={{ fontSize: 9, color: T.textSec, marginBottom: 2 }}>{a}</div>
                      <div style={{ height: 16, background: T.surfaceAlt, borderRadius: 3, position: 'relative', overflow: 'hidden' }}>
                        <div style={{ position: 'absolute', left: '50%', top: 0, bottom: 0, width: 1, background: T.border }} />
                        {(isPos || isNeg) && <div style={{
                          position: 'absolute', top: 2, bottom: 2,
                          left: isPos ? '50%' : `${50 - pct * 50}%`,
                          width: `${pct * 50}%`,
                          background: isPos ? T.green : T.red,
                          borderRadius: 2, transition: 'all 0.3s',
                          opacity: 0.7,
                        }} />}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          ))}
        </div>

        {/* Insight */}
        <div style={{
          background: T.surfaceAlt, borderRadius: 8, padding: '10px 14px',
          borderLeft: '3px solid ' + T.purple, fontSize: 11, color: T.textSec, lineHeight: 1.5,
        }}>
          <span style={{ color: T.purple, fontWeight: 700 }}>Insight: </span>
          {insight.text}
        </div>
      </div>
    </div>
  );
}
